class KernelCa6k00266Custom {
public:
    __aicore__ inline void Init(GM_ADDR weight, GM_ADDR indices, GM_ADDR offsets, GM_ADDR output,
                                uint32_t totalBags, uint32_t embeddingDim, uint32_t tileDim) {
        weightGm_.SetGlobalBuffer((__gm__ float*)weight, numEmbeddings * embeddingDim);
        indicesGm_.SetGlobalBuffer((__gm__ int32_t*)indices, totalIndices);
        offsetsGm_.SetGlobalBuffer((__gm__ int32_t*)offsets, totalBags+1);
        outputGm_.SetGlobalBuffer((__gm__ float*)output, totalBags * embeddingDim);
        totalBags_ = totalBags;
        embeddingDim_ = embeddingDim;
        tileDim_ = tileDim;
        // Initialize pipe and queues
        pipe_.InitBuffer(inQueueX_, 1, tileDim_ * sizeof(float)); // weight row tile
        pipe_.InitBuffer(outQueueY_, 1, tileDim_ * sizeof(float)); // output tile accumulator
    }

    __aicore__ inline void Process() {
        // Each block processes a subset of bags
        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t blockNum = AscendC::GetBlockNum();
        for (uint32_t bag = blockIdx; bag < totalBags_; bag += blockNum) {
            int32_t start = offsetsGm_[bag];
            int32_t end = offsetsGm_[bag+1];
            // accumulate output row
            // We'll accumulate into a local tensor tile by tile.
            // For each tile offset
            AscendC::LocalTensor<float> outTile = outQueueY_.AllocTensor<float>();
            // Initialize to zero
            AscendC::SetZero(outTile, tileDim_);
            for (int32_t i = start; i < end; i++) {
                int32_t idx = indicesGm_[i];
                // Load weight row tile
                for (uint32_t t = 0; t < embeddingDim_; t += tileDim_) {
                    uint32_t curTile = (embeddingDim_ - t > tileDim_) ? tileDim_ : embeddingDim_ - t;
                    AscendC::LocalTensor<float> wTile = inQueueX_.AllocTensor<float>();
                    AscendC::DataCopy(wTile, weightGm_[idx * embeddingDim_ + t], curTile);
                    // Add to outTile
                    AscendC::Add(outTile, outTile, wTile, curTile);
                    inQueueX_.FreeTensor(wTile);
                }
            }
            // Write output row
            for (uint32_t t = 0; t < embeddingDim_; t += tileDim_) {
                uint32_t curTile = (embeddingDim_ - t > tileDim_) ? tileDim_ : embeddingDim_ - t;
                AscendC::DataCopy(outputGm_[bag * embeddingDim_ + t], outTile, curTile);
            }
            outQueueY_.FreeTensor(outTile);
        }
    }
};

